const c = $input.first().json;
const score = (typeof c.score === 'number') ? c.score.toFixed(2) : '–';
const takenDate = c.taken_at ? c.taken_at.slice(0, 10) : '';
const lines = [
  '<b>📸 New candidate</b>',
  '',
  '<b>File:</b> ' + (c.filename || c.asset_id),
];
if (takenDate) lines.push('<b>Taken:</b> ' + takenDate);
lines.push('<b>Score:</b> ' + score + (c.has_embedding ? '' : ' (no embedding yet)'));
lines.push('', 'Approve to queue for posting, reject to mark seen.');
return [{ json: { asset_id: c.asset_id, caption: lines.join('\n') } }];
